import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Logs hochladen","description":"Wie man Logs zur Fehlerbehebung hochlädt.","frontmatter":{"title":"Logs hochladen","description":"Wie man Logs zur Fehlerbehebung hochlädt.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"de_de/1.21.4/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.4/translated/de_de/players/troubleshooting/uploading-logs.md","lastUpdated":1760721669000}`);var a={name:`de_de/1.21.4/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Logs hochladen <a class="header-anchor" href="#h1" aria-label="Permalink to “Logs hochladen”">​</a></h1><p>Wenn man versucht, Fehler zu beheben, ist es oft nötig, Logs bereitzustellen, die beim Identifizieren der Ursache des Fehlers helfen.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Warum sollte ich Logs hochladen? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Warum sollte ich Logs hochladen?”">​</a></h2><p>Das Hochladen von Logs ermöglicht es anderen, dir bei der Fehlersuche schneller zu helfen, als wenn die Logs in den Chat oder Forenbeiträge eingefügt werden. Es ermöglicht dir auch, die Logs mit anderen zu teilen, ohne sie zu Kopieren oder Einfügen zu müssen.</p><p>Manche Paste-Seiten stellen Syntaxhervorhebung für Logs bereit, was sie deutlich einfacher zu lesen macht und zensieren sensible Daten, wie Benutzernamen oder Systeminformationen.</p><h2 id="crash-reports" tabindex="-1">Absturzberichte <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Absturzberichte”">​</a></h2><p>Absturzberichte werden automatisch generiert, wenn das Spiel abstürzt. Sie enthalten nur Absturzinformationen, aber nicht die eigentlichen Logs des Spiels. Sie befinden sich im <code>crash-reports</code>-Verzeichnis im Spiel-Verzeichnis.</p><p>Für weitere Informationen über Absturzberichte, siehe <a href="./crash-reports">Absturzberichte</a>.</p><h2 id="locating-logs" tabindex="-1">Logs finden <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Logs finden”">​</a></h2><p>Diese Anleitung behandelt den offiziellen Minecraft-Launcher (oft auch &quot;Vanilla-Launcher&quot; genannt) - für Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><p>Logs befinden sich im <code>logs</code>-Verzeichnis innerhalb des Spiel-Verzeichnisses, das Spiel-Verzeichnis kann sich, abhängig von deinem Betriebssystem, an den folgenden Orten befinden:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Das neueste Log hat den Dateinamen <code>latest.log</code> und vorherige Logs nutzen das Muster <code>JJJJ-MM-TT_Nummer.log.gz</code> zur Benennung.</p><h2 id="uploading-logs-online" tabindex="-1">Logs hochladen <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Logs hochladen”">​</a></h2><p>Logs können bei einer Vielzahl von Diensten hochgeladen werden, zum Beispiel:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};